mapper.select:
SELECT b.id, b.user_id, b.seat_id, b.space_id, b.booking_date, b.start_time, b.end_time, b.status, b.cancel_reason, s.seat_number, sp.name as space_name, u.username as user_name, u.real_name as user_real_name, u.student_id as user_student_id FROM booking b LEFT JOIN seat s ON b.seat_id = s.id LEFT JOIN space sp ON b.space_id = sp.id LEFT JOIN sys_user u ON b.user_id = u.id WHERE b.user_id = #{userId}
AND b.status = #{status}
AND b.deleted = 0 ORDER BY b.booking_date DESC, b.start_time DESC

SELECT b.id, b.user_id, b.seat_id, b.space_id, b.booking_date, b.start_time, b.end_time, b.status, b.cancel_reason, s.seat_number, sp.name as space_name, u.username as user_name, u.real_name as user_real_name, u.student_id as user_student_id FROM booking b LEFT JOIN seat s ON b.seat_id = s.id LEFT JOIN space sp ON b.space_id = sp.id LEFT JOIN sys_user u ON b.user_id = u.id WHERE b.deleted = 0
AND sp.name LIKE CONCAT('%', #{spaceName}, '%')
AND s.seat_number LIKE CONCAT('%', #{seatNumber}, '%')
AND b.booking_date = #{bookingDate}
AND b.status = #{status}
ORDER BY b.booking_date DESC, b.start_time DESC
